async def main():
    print("--- Testing character mapping & gender extraction with user's story ---")
    tagged_story = await inject_speaker_tags_to_story(user_story, supports_emotions=True)
    
    print("\n--- 1. Speaker Mapping & Genders from tagged output ---")
    if "speaker_mapping" in tagged_story:
        print(json.dumps(tagged_story["speaker_mapping"], indent=2, ensure_ascii=False))
    else:
        print("No speaker mapping found in returned data!")
        
    print("\n--- 2. Extracted Speakers (API format) ---")
    speakers = await extract_speakers_from_tagged_story(tagged_story)
    print(json.dumps(speakers, indent=2, ensure_ascii=False))
    
    print("\n--- 3. Sample output from chapters with tags (first 500 chars of each) ---")
    for idx, chap in enumerate(tagged_story.get("chapters", [])):
        print(f"\n[Chapter {idx + 1}]:")
        print(chap.get("text")[:600] + "...")

if __name__ == "__main__":
    asyncio.run(main())
